@@ -67,7 +67,9 @@ public class KafkaFutureImpl<T> extends KafkaFuture<T> {
                     // maintain the KafkaFuture behaviour.
                     throw new CompletionException(t);
                 } else {
-                    throw t;
+                    // Wrap in CompletionException to preserve the original exception as the cause,
+                    // so callers see ExecutionException -> CompletionException -> original exception.
+                    throw new CompletionException(t.getMessage(), t);
                 }
             }
         });
